// src/client/scripts/todos.ts
redirectIfGuest();
await loadLanguage();
var { user } = await api.get("/api/auth/me");
document.body.prepend(Navbar({ userName: user.name }));
var list = document.getElementById("todo-list");
var form = document.getElementById("add-form");
